export function findSimulation(query: string): Simulation | null {
  const q = query.toLowerCase().trim();
  // Exact match first
  for (const [kw, id] of Object.entries(TOPIC_MAP)) {
    if (q === kw || q.includes(kw)) {
      return S.find(s => s.id === id) || null;
    }
  }
  // Fuzzy: check each word
  const words = q.split(/\s+/);
  for (const w of words) {
    if (w.length > 3 && TOPIC_MAP[w]) {
      return S.find(s => s.id === TOPIC_MAP[w]) || null;
    }
  }
  return null;
}

export function getAllSimulations(): Simulation[] { return S; }
export function getSimulationById(id: string): Simulation | null { return S.find(s => s.id === id) || null; }
